parameters.query:
SELECT topic, keywords, category
FROM news_topics
WHERE is_active = TRUE
ORDER BY id ASC;

DELETE FROM news_summaries;

parameters.jsCode:
const items = $input.all();

// ── FIXED FETCH LOOP DATA ──
// We use the linked item context to ensure the topic matches the current loop cycle
let topic = 'general';
let keywords = 'news';

try {
  // $(nodeName).item refers to the specific input item mapped to this execution
  const loopData = $('Loop Over Topics').item.json;
  topic = loopData.topic || topic;
  keywords = loopData.keywords || keywords;
} catch (e) {
  // Fallback: check if topic exists on the incoming $json directly
  topic = $json.topic || topic;
}

// ── STORAGE ──
const articles = [];
const seenUrls = new Set();
const seenTitles = new Set();

// ── PROCESS INPUT ──
for (const item of items) {
  const d = item.json;

  // ───────── NEWSAPI PARSER ─────────
  if (d.articles && Array.isArray(d.articles)) {
    for (const article of d.articles) {
      let url = (article.url || '').trim();
      let title = (article.title || '').toLowerCase().replace(/\s+/g, ' ').trim();

      if (!url || !title || url.includes('removed')) continue;

      url = url.split('?')[0]; // Normalize URL

      if (seenUrls.has(url) || seenTitles.has(title)) continue;

      seenUrls.add(url);
      seenTitles.add(title);

      const articleId = `ART-${topic.replace(/\s+/g, '-')}-${Math.abs(url.split('').reduce((a, c) => a + c.charCodeAt(0), 0))}`;

      articles.push({
        article_id: articleId,
        topic: topic,
        title: article.title || '',
        description: (article.description || '').substring(0, 500),
        content: (article.content || '').substring(0, 1000),
        url: url,
        source_name: article.source?.name || 'NewsAPI',
        author: article.author || '',
        published_at: article.publishedAt || new Date().toISOString(),
        fetch_source: 'newsapi'
      });
    }
  }

  // ───────── FIRECRAWL / GOOGLE NEWS PARSER ─────────
  if (d.data?.content || d.data?.markdown) {
    const rawContent = d.data.markdown || d.data.content;

    // Split by Markdown links which usually indicate a new headline in Google News
    const sections = rawContent.split(/\[([^\]]+)\]\((https:\/\/news\.google\.com\/read\/[^\)]+)\)/g);

    for (let i = 1; i < sections.length; i += 2) {
      const title = sections[i].trim();
      const url = sections[i + 1].trim();
      const normalizedTitle = title.toLowerCase();

      if (!title || title.length < 10 || seenTitles.has(normalizedTitle)) continue;

      seenTitles.add(normalizedTitle);

      articles.push({
        article_id: `FC-${topic.replace(/\s+/g, '-')}-${i}-${Date.now()}`,
        topic: topic,
        title: title.substring(0, 200),
        description: `Latest news about ${topic} from Google News.`,
        content: title,
        url: url,
        source_name: 'Google News',
        author: '',
        published_at: new Date().toISOString(),
        fetch_source: 'firecrawl'
      });
    }
  }
}

// ── SORT BY DATE (LATEST FIRST) ──
articles.sort((a, b) => new Date(b.published_at) - new Date(a.published_at));

// ── LIMIT ──
const top10 = articles.slice(0, 10);

// ── FAILSAFE ──
if (top10.length === 0) {
  return [{
    json: {
      topic: topic,
      error: true,
      message: 'No articles found for: ' + topic
    }
  }];
}

// ── RETURN ──
return top10.map(a => ({ json: a }));

parameters.text:
=Analyze these news headlines and generate an intelligence briefing.

News Headlines:
{{ $input.all().slice(0,5).map((i,idx)=>
`${idx+1}. ${i.json.title}`
).join('\n') }}

Return this exact JSON format:

{
  "headline": "Biggest story today",
  "top_stories": [
    {
      "rank": 1,
      "title": "",
      "summary": "",
      "importance": "High",
      "source": ""
    }
  ],
  "key_insight": "",
  "sentiment": "",
  "trend": ""
}

parameters.jsCode:
const items = $input.all();
const results = [];
const seenHeadlines = new Set();

for (const item of items) {
  let raw = item.json.output;

  if (!raw) continue;

  try {
    // Parse string → JSON
    const data = JSON.parse(raw);

    const headline = (data.headline || '')
      .toLowerCase()
      .trim();

    // Deduplicate
    if (seenHeadlines.has(headline)) continue;
    seenHeadlines.add(headline);

    // Fix bad URLs
    let story = data.top_stories?.[0] || {};

    let url = story.url || '';
    if (!url.startsWith('http')) {
      url = null; // clean invalid links
    }

    results.push({
      json: {
        topic: data.topic || 'general',
        headline: data.headline || '',
        title: story.title || '',
        summary: story.summary || '',
        importance: story.importance || 'Medium',
        source: story.source || '',
        url: url,
        key_insight: data.key_insight || '',
        sentiment: data.sentiment || 'Neutral',
        trend: data.trend || 'Stable',
        created_at: new Date().toISOString()
      }
    });

  } catch (e) {
    // Skip bad JSON safely
    continue;
  }
}

// Limit results
return results.slice(0, 5);

const items = $input.all();

// ── EMOJIS ──
const topicEmojis = {
  'AI': '🤖', 'Finance': '💰',
  'Geopolitics': '🌍', 'Crypto': '₿',
  'Health': '🏥', 'Space': '🚀',
  'Sports': '⚽', 'Tech': '💻'
};

const sentimentEmojis = {
  'Bullish': '📈', 'Bearish': '📉',
  'Neutral': '➡️', 'Alarming': '🚨',
  'Optimistic': '✅'
};

// ── STEP 1: DEDUPLICATION (topic + headline) ──
const seen = new Set();
const uniqueItems = [];

for (const item of items) {
  const d = item.json;

  const key =
    (d.topic || '') + '|' +
    (d.headline || '')
      .toLowerCase()
      .replace(/[^\w\s]/g, '')
      .trim();

  if (!seen.has(key)) {
    seen.add(key);
    uniqueItems.push(d);
  }
}

// ── BUILD EMAIL HTML ──
let emailHtml = `
<div style="font-family:Arial,sans-serif;
            max-width:700px;margin:0 auto;
            background:#f5f5f5;padding:20px;">

  <div style="background:linear-gradient(
              135deg,#1a1a2e,#16213e);
              color:white;padding:30px;
              border-radius:12px;
              text-align:center;
              margin-bottom:20px;">
    <h1 style="margin:0;font-size:28px;">
      📰 News Intelligence Briefing
    </h1>
    <p style="margin:10px 0 0;opacity:0.8;">
      ${new Date().toLocaleDateString('en-US', {
        weekday: 'long',
        year: 'numeric',
        month: 'long',
        day: 'numeric'
      })}
    </p>
  </div>
`;

// ── LOOP THROUGH CLEAN DATA ──
for (const d of uniqueItems) {

  const emoji = topicEmojis[d.topic] || '📌';
  const sentEmoji = sentimentEmojis[d.sentiment] || '➡️';

  // ── SAFE PARSE STORIES ──
  let stories = [];

  if (typeof d.top_articles === 'string') {
    try {
      const parsed = JSON.parse(d.top_articles);

      if (Array.isArray(parsed)) {
        stories = parsed;
      } else {
        // fallback (your case)
        stories = [{
          title: d.headline,
          summary: d.top_articles,
          source: '',
          importance: 'High'
        }];
      }
    } catch {
      // fallback (non-JSON string)
      stories = [{
        title: d.headline,
        summary: d.top_articles,
        source: '',
        importance: 'High'
      }];
    }
  } else if (Array.isArray(d.top_articles)) {
    stories = d.top_articles;
  }

  // fallback if empty
  if (stories.length === 0) {
    stories = [{
      title: d.headline,
      summary: '',
      source: '',
      importance: 'Medium'
    }];
  }

  const sentimentColors = {
    'Bullish': '#28a745',
    'Bearish': '#dc3545',
    'Neutral': '#6c757d',
    'Alarming': '#fd7e14',
    'Optimistic': '#20c997'
  };

  const sentColor = sentimentColors[d.sentiment] || '#6c757d';

  emailHtml += `
  <div style="background:white;
              border-radius:12px;
              margin-bottom:20px;
              overflow:hidden;
              box-shadow:0 2px 8px 
                         rgba(0,0,0,0.1);">

    <div style="padding:20px;
                border-left:5px solid ${sentColor};
                background:#fafafa;">
      <div style="display:flex;
                  justify-content:space-between;
                  align-items:center;">
        <h2 style="margin:0;color:#1a1a2e;
                   font-size:20px;">
          ${emoji} ${d.topic}
        </h2>
        <span style="background:${sentColor};
                     color:white;
                     padding:4px 12px;
                     border-radius:20px;
                     font-size:13px;">
          ${sentEmoji} ${d.sentiment}
        </span>
      </div>
      <p style="margin:8px 0 0;
                color:#555;
                font-style:italic;
                font-size:15px;">
        ${d.headline || ''}
      </p>
    </div>

    <div style="padding:15px 20px;">
  `;

  for (let i = 0; i < stories.length; i++) {
    const story = stories[i];

    const importanceColors = {
      'High': '#dc3545',
      'Medium': '#fd7e14',
      'Low': '#28a745'
    };

    const impColor =
      importanceColors[story.importance] || '#6c757d';

    emailHtml += `
      <div style="padding:12px 0;
                  border-bottom:1px solid #f0f0f0;">
        <div style="display:flex;
                    align-items:center;
                    gap:8px;margin-bottom:4px;">
          <span style="background:${impColor};
                       color:white;
                       padding:2px 8px;
                       border-radius:4px;
                       font-size:11px;
                       font-weight:bold;">
            ${story.importance || 'Medium'}
          </span>
          <span style="color:#999;font-size:12px;">
            ${story.source || ''}
          </span>
        </div>
        <p style="margin:4px 0;
                  font-weight:bold;
                  color:#1a1a2e;
                  font-size:15px;">
          ${story.title || ''}
        </p>
        <p style="margin:4px 0;
                  color:#555;
                  font-size:14px;
                  line-height:1.5;">
          ${story.summary || ''}
        </p>
        ${story.url ? `
        <a href="${story.url}"
           style="color:#007bff;
                  font-size:13px;
                  text-decoration:none;">
          Read full story →
        </a>` : ''}
      </div>
    `;
  }

  emailHtml += `
    </div>

    <div style="background:#fff3cd;
                padding:15px 20px;
                border-top:1px solid #ffd93d;">
      <strong>💡 Key Insight:</strong>
      ${d.key_insight || ''}
    </div>
  </div>
  `;
}

emailHtml += `
  <div style="text-align:center;
              color:#999;font-size:12px;
              padding:20px;">
    Generated by News Intelligence Dashboard
    <br>Powered by n8n + OpenAI + NewsAPI
  </div>
</div>
`;

// ── TELEGRAM MESSAGE ──
let telegramMsg =
  `📰 *Daily News Briefing*\n` +
  `_${new Date().toDateString()}_\n\n`;

for (const d of uniqueItems) {

  const emoji = topicEmojis[d.topic] || '📌';
  const sentEmoji = sentimentEmojis[d.sentiment] || '➡️';

  let stories = [];

  try {
    const parsed = JSON.parse(d.top_articles);
    stories = Array.isArray(parsed) ? parsed : [];
  } catch {
    stories = [{
      title: d.headline,
      summary: d.top_articles
    }];
  }

  telegramMsg +=
    `${emoji} *${d.topic}* ${sentEmoji} ${d.sentiment}\n` +
    `📌 ${d.headline || ''}\n\n`;

  stories.slice(0, 3).forEach((s, i) => {
    telegramMsg +=
      `${i+1}. *${s.title || ''}*\n` +
      `${s.summary || ''}\n`;

    if (s.url) {
      telegramMsg += `🔗 ${s.url}\n`;
    }

    telegramMsg += '\n';
  });

  telegramMsg +=
    `💡 _${d.key_insight || ''}_\n` +
    `${'─'.repeat(30)}\n\n`;
}

// ── FINAL OUTPUT ──
return [{
  json: {
    email_html: emailHtml,
    telegram_msg: telegramMsg,
    topics_covered: uniqueItems
      .map(i => i.topic).join(', '),
    total_topics: uniqueItems.length,
    generated_at: new Date().toISOString()
  }
}];

const items = $input.all();

function cleanText(text = '') {
  return text
    // remove markdown images
    .replace(/!\[.*?\]\(.*?\)/g, '')

    // remove urls
    .replace(/https?:\/\/\S+/g, '')

    // remove extra markdown
    .replace(/\*+/g, '')

    // remove excessive whitespace
    .replace(/\s+/g, ' ')

    .trim();
}

const cleaned = items
  .map(item => {
    const d = item.json;

    let title = cleanText(d.title || '');
    let url = d.url || '';

    // Sometimes title/url swapped
    if (title.startsWith('http')) {
      title = cleanText(url);
      url = d.title || '';
    }

    return {
      json: {
        topic: d.topic,
        source_name: d.source_name,
        title,
        description: cleanText(d.description || ''),
        url,
        published_at: d.published_at
      }
    };
  })

  // remove garbage titles
  .filter(i =>
    i.json.title &&
    i.json.title.length > 20 &&
    !i.json.title.includes('There are no items to show')
  )

  // keep only best 5
  .slice(0, 5);

return cleaned;
